#!/usr/bin/env python3
import json, os, sys, math, collections, itertools
from pathlib import Path
sys.path.insert(0, str(Path(__file__).resolve().parent))
from cost_model import CostModel, HEADS, HIDDEN, align

ROOT = Path('/app/task_file')
GRAN = 64
MAX_SHAPES = 8
CM = CostModel(GRAN)

def load(path):
    return [json.loads(l) for l in open(path)]

def save(path, recs):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f:
        for r in recs:
            f.write(json.dumps(r) + '\n')

def shape_compile_cost(s):
    return CM.c.Kshape_attn * (s ** 2) + CM.c.Kshape_mlp * (s * HIDDEN)

def choose_global_shapes(buckets, k=MAX_SHAPES, compile_weight=1e-4):
    # all aligned prompt candidates across both buckets
    cand = sorted({align(r['prompt_len'], GRAN) for reqs in buckets.values() for r in reqs})
    maxs = cand[-1]
    # weighted prompt padding only for shape selection; compile cost small tie-breaker
    weights = collections.Counter()
    for reqs in buckets.values():
        for r in reqs:
            weights[align(r['prompt_len'], GRAN)] += 1
    n = len(cand)
    # dp[j][kk] = (best_score, prev_j, prev_kk)
    INF = float('inf')
    dp = [[INF] * (k + 1) for _ in range(n + 1)]
    par = [[None] * (k + 1) for _ in range(n + 1)]
    dp[0][0] = 0.0
    for i in range(n):
        for kk in range(k + 1):
            if dp[i][kk] == INF:
                continue
            # skip candidate i
            if dp[i+1][kk] > dp[i][kk]:
                dp[i+1][kk] = dp[i][kk]
                par[i+1][kk] = (i, kk, False)
            # take candidate i as a selected shape
            if kk < k:
                # requests with aligned seq in (prev_selected, cand[i]] are assigned to cand[i]
                # prev_selected index is implicit via path; compute incremental padding using all buckets
                # We need the previous selected candidate index. Reconstruct selected so far by backtracking would be slow;
                # instead compute padding directly from selected set when finalizing.
                score = dp[i][kk] + 0  # placeholder; we will use a different method below
                # This DP is awkward for coverage ranges; use brute force over small candidate set instead.
    # Candidate set is small enough (<=24+11=35); prune to important candidates and brute force up to 8.
    # Pruning: keep all bucket1 unique high shapes because they are sparse and costly to overpad;
    # plus a grid for low shapes where most requests live.
    low_grid = list(range(64, 768, 64))
    high_b1 = sorted(set(align(r['prompt_len'], GRAN) for r in buckets['1'] if align(r['prompt_len'], GRAN) >= 768))
    high_b2 = sorted(set(align(r['prompt_len'], GRAN) for r in buckets['2'] if align(r['prompt_len'], GRAN) >= 768))
    cand_pruned = sorted(set(low_grid + high_b1 + high_b2))
    if maxs not in cand_pruned:
        cand_pruned.append(maxs)
    # Always include 64 and maxs for feasible coverage.
    # Brute force combinations including maxs; limit to pruned candidates.
    best = None
    for kk in range(1, min(k, len(cand_pruned)) + 1):
        for combo in itertools.combinations(cand_pruned, kk):
            reps = sorted(combo)
            if reps[0] != 64 or reps[-1] != maxs:
                continue
            pad = 0
            for reqs in buckets.values():
                for r in reqs:
                    s = align(r['prompt_len'], GRAN)
                    rep = maxs
                    for x in reps:
                        if x >= s:
                            rep = x
                            break
                    pad += rep - r['prompt_len']
            score = pad + compile_weight * sum(shape_compile_cost(s) for s in reps)
            if best is None or score < best[0]:
                best = (score, reps)
    return best[1]

def assign_shape(reqs, reps):
    out = []
    reps = sorted(reps)
    for r in reqs:
        s = align(r['prompt_len'], GRAN)
        rep = reps[-1]
        for x in reps:
            if x >= s:
                rep = x
                break
        rr = dict(r)
        rr['shape_seq'] = rep
        out.append(rr)
    return out

def build_plan(reqs, reps):
    assigned = assign_shape(reqs, reps)
    by_shape = collections.defaultdict(list)
    for r in assigned:
        by_shape[r['shape_seq']].append(r)
    recs = []
    bid = 0
    for s in sorted(by_shape):
        # group by exact gen_len to eliminate decode padding
        by_gen = collections.defaultdict(list)
        for r in by_shape[s]:
            by_gen[r['gen_len']].append(r)
        for g in sorted(by_gen):
            bid += 1
            batch_id = f'b{bid:04d}'
            for r in by_gen[g]:
                recs.append({
                    'request_id': r['request_id'],
                    'batch_id': batch_id,
                    'shape': {'seq_align': s, 'heads_align': HEADS, 'hidden_align': HIDDEN}
                })
    return recs

def main():
    b1 = load(str(ROOT / 'input_data' / 'requests_bucket_1.jsonl'))
    b2 = load(str(ROOT / 'input_data' / 'requests_bucket_2.jsonl'))
    reps = choose_global_shapes({'1': b1, '2': b2}, MAX_SHAPES)
    plan1 = build_plan(b1, reps)
    plan2 = build_plan(b2, reps)
    save(str(ROOT / 'output_data' / 'plan_b1.jsonl'), plan1)
    save(str(ROOT / 'output_data' / 'plan_b2.jsonl'), plan2)
    print('global shapes:', reps)

if __name__ == '__main__':
    main()
